import{_ as r,c as o,o as d,ag as a}from"./chunks/framework.XjE0kKti.js";const n="/gatewayweb/docs/assets/hub0042-overview.CmP6uLv2.png",s="/gatewayweb/docs/assets/hub0042-service-context.DSkCiQUd.png",p=JSON.parse('{"title":"服务列表（hub0042）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0042.md","filePath":"modules/hub0042.md","lastUpdated":1776841524000}'),e={name:"modules/hub0042.md"};function h(g,t,l,i,b,u){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="服务列表-hub0042" tabindex="-1">服务列表（hub0042） <a class="header-anchor" href="#服务列表-hub0042" aria-label="Permalink to &quot;服务列表（hub0042）&quot;">​</a></h1><p>本页在<strong>上下分栏</strong>中同时展示 <strong>命名空间</strong> 与 <strong>服务</strong>：先在上方选中一个命名空间，再在下方对该空间内的服务做查询、新建、编辑、删除及查看详情。命名空间的新增与删改请在 <strong><a href="./hub0041.html">命名空间管理（hub0041）</a></strong> 完成；本页内嵌的命名空间列表以筛选与查看为主。</p><p><img src="'+n+'" alt="命名空间与服务列表总览"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>命名空间选择</td><td>单击命名空间行，加载该空间下的服务列表。</td></tr><tr><td>服务维护</td><td>新建、编辑、删除服务；支持按名称、分组、类型、活动状态筛选。</td></tr><tr><td>服务详情</td><td>全页展示服务元数据与<strong>服务实例列表</strong>（节点健康情况）。</td></tr><tr><td>与注册中心对齐</td><td>服务类型支持内部服务、Nacos、Consul、Eureka、ETCD、ZooKeeper 等（与表单选项一致）。</td></tr></tbody></table><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>服务治理</strong> → <strong>服务列表</strong>。</p><hr><h2 id="上半区-命名空间列表-内嵌" tabindex="-1">上半区：命名空间列表（内嵌） <a class="header-anchor" href="#上半区-命名空间列表-内嵌" aria-label="Permalink to &quot;上半区：命名空间列表（内嵌）&quot;">​</a></h2><ul><li><strong>筛选</strong>：命名空间名称、服务中心实例（「…」选择器）、部署环境、活动状态；使用 <strong>查询</strong> / <strong>重置</strong> 刷新列表。</li><li><strong>行单击</strong>：选中该命名空间，并<strong>自动加载</strong>下方「该命名空间下」的服务列表。</li><li><strong>右键菜单</strong>：仅提供 <strong>查看详情</strong>（内嵌场景下不提供命名空间的编辑/删除，完整 CRUD 请使用 <a href="./hub0041.html">hub0041</a>）。</li></ul><p>未选中命名空间时，下方服务的 <strong>查询</strong>、<strong>新建服务</strong> 以及分页会受限：界面会提示「请先在上方命名空间列表中选择一个命名空间」；取消选择命名空间时，下方服务列表会被清空。</p><hr><h2 id="下半区-服务列表" tabindex="-1">下半区：服务列表 <a class="header-anchor" href="#下半区-服务列表" aria-label="Permalink to &quot;下半区：服务列表&quot;">​</a></h2><h3 id="筛选条件" tabindex="-1">筛选条件 <a class="header-anchor" href="#筛选条件" aria-label="Permalink to &quot;筛选条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>服务名称</strong></td><td>占位：请输入服务名称。</td></tr><tr><td><strong>分组名称</strong></td><td>占位：请输入分组名称。</td></tr><tr><td><strong>服务类型</strong></td><td>全部 / 内部服务 / Nacos / Consul / Eureka / ETCD / ZooKeeper。</td></tr><tr><td><strong>活动状态</strong></td><td>全部 / 活动 / 非活动。</td></tr></tbody></table><p>查询结果始终限定在<strong>当前选中的命名空间</strong>内（由程序自动带上 <code>namespaceId</code>）。</p><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新建服务</strong></td><td>打开「新增服务」对话框；<strong>命名空间 ID</strong> 从当前选中行自动带入且不可改。未选命名空间时会提示先选择。</td></tr><tr><td><strong>编辑</strong></td><td>优先使用<strong>勾选行</strong>；若无勾选则使用<strong>当前高亮行</strong>。必须且仅能选中 <strong>1</strong> 条，否则会提示「请先选择」或「只能编辑一个服务」。</td></tr><tr><td><strong>删除</strong></td><td>支持勾选<strong>多条</strong>批量删除，确认后逐条调用删除接口。</td></tr><tr><td><strong>查询 / 重置</strong></td><td>刷新服务列表或清空服务筛选条件（仍需已选命名空间）。</td></tr></tbody></table><h3 id="表格列说明" tabindex="-1">表格列说明 <a class="header-anchor" href="#表格列说明" aria-label="Permalink to &quot;表格列说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>含义</th></tr></thead><tbody><tr><td>命名空间 ID</td><td>所属命名空间；与上方选中行一致。</td></tr><tr><td>分组名称</td><td>逻辑分组，常见为 <code>DEFAULT_GROUP</code>；列表中以标签样式展示。</td></tr><tr><td>服务名称</td><td>注册服务名；列表中以圆角标签展示。</td></tr><tr><td>服务类型</td><td>如内部服务、Nacos 等。</td></tr><tr><td>服务版本 / 服务描述</td><td>无内容时显示为 <code>-</code>。</td></tr><tr><td>节点数量 / 健康节点 / 不健康节点</td><td>反映已注册实例规模与健康度，便于一眼判断是否需要排查节点或网络。</td></tr><tr><td>活动状态</td><td>活动 / 非活动。</td></tr><tr><td>创建与修改信息</td><td>审计字段。</td></tr></tbody></table><p>分组、服务名称的标签颜色由名称哈希稳定映射，<strong><code>DEFAULT_GROUP</code></strong> 使用固定默认色系，便于快速识别。</p><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p><img src="'+s+'" alt="服务列表右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据 / 复制单元格</strong></td><td>表格通用能力。</td></tr><tr><td><strong>查看详情</strong></td><td>进入<strong>全页「服务详情」</strong>（非弹窗简要查看）：左侧为服务基本信息与元数据 JSON，右侧为 <strong>服务实例列表</strong>，可结合节点展示做运维排查。</td></tr><tr><td><strong>编辑</strong></td><td>打开「编辑服务」对话框（拉取最新详情后再编辑）。</td></tr><tr><td><strong>删除</strong></td><td>删除当前行对应服务（有确认流程）。</td></tr></tbody></table><hr><h2 id="新增-编辑服务对话框" tabindex="-1">新增 / 编辑服务对话框 <a class="header-anchor" href="#新增-编辑服务对话框" aria-label="Permalink to &quot;新增 / 编辑服务对话框&quot;">​</a></h2><ul><li><strong>新增</strong>：标题为 <strong>新增服务</strong>。</li><li><strong>编辑</strong>：标题为 <strong>编辑服务</strong>；<strong>分组名称</strong>、<strong>服务名称</strong> 为联合主键的一部分，编辑模式下<strong>不允许修改</strong>（以界面禁用状态为准）。</li></ul><h3 id="tab-基本信息" tabindex="-1">Tab：基本信息 <a class="header-anchor" href="#tab-基本信息" aria-label="Permalink to &quot;Tab：基本信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>命名空间 ID</strong></td><td>必填、只读，来自上方选中的命名空间。</td></tr><tr><td><strong>分组名称</strong></td><td>必填，默认常见为 <code>DEFAULT_GROUP</code>。</td></tr><tr><td><strong>服务名称</strong></td><td>必填。</td></tr><tr><td><strong>服务类型</strong></td><td>必填，默认内部服务。</td></tr><tr><td><strong>服务版本</strong></td><td>可选。</td></tr><tr><td><strong>服务描述</strong></td><td>可选多行。</td></tr><tr><td><strong>活动状态</strong></td><td>开关。</td></tr></tbody></table><h3 id="tab-服务配置" tabindex="-1">Tab：服务配置 <a class="header-anchor" href="#tab-服务配置" aria-label="Permalink to &quot;Tab：服务配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>保护阈值</strong></td><td>0.00～1.00，表示健康实例比例低于该值时触发保护策略。</td></tr><tr><td><strong>外部服务配置</strong></td><td>JSON，用于外部注册中心等连接信息。</td></tr><tr><td><strong>服务元数据 / 服务标签 / 服务选择器</strong></td><td>JSON 文本，扩展字段与路由选择逻辑。</td></tr></tbody></table><h3 id="tab-其它" tabindex="-1">Tab：其它 <a class="header-anchor" href="#tab-其它" aria-label="Permalink to &quot;Tab：其它&quot;">​</a></h3><p>备注及创建/修改审计字段（只读为主）。</p><hr><h2 id="服务详情页" tabindex="-1">服务详情页 <a class="header-anchor" href="#服务详情页" aria-label="Permalink to &quot;服务详情页&quot;">​</a></h2><p>从右键 <strong>查看详情</strong> 进入后，顶部为 <strong>服务详情</strong> 标题，提供：</p><ul><li><strong>编辑服务</strong>：关闭详情页并打开编辑对话框。</li><li><strong>返回</strong>：回到上下分栏列表视图。</li></ul><p>详情中会展示 <strong>服务实例列表</strong>；实例区域支持刷新（具体按钮以界面为准）。<strong>集群配置</strong>、<strong>节点编辑</strong> 等若在界面中提示「开发中」，表示后续版本开放。</p><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li>先确认 <strong><a href="./hub0040.html">服务中心实例（hub0040）</a></strong> 与 <strong><a href="./hub0041.html">命名空间（hub0041）</a></strong> 已就绪，再在本页选择命名空间维护服务。</li><li>观察 <strong>健康节点 / 不健康节点</strong>：长期为 0 可能是尚未注册实例，或 SDK 未连上对应命名空间。</li><li>批量删除前请确认下游无硬编码依赖该 <code>groupName + serviceName</code>。</li></ol>',43)])])}const m=r(e,[["render",h]]);export{p as __pageData,m as default};
